// frontend/src/components/RunningModelBackground.jsx

import React, { useRef, Suspense } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { useGLTF, Environment } from '@react-three/drei';

function RunnerModel() {
    // 1. CALL HOOKS AT THE TOP LEVEL (OUTSIDE try/catch)
    // useGLTF will throw an error if the model fails to load,
    // which is why it must be caught by the parent <Suspense> component.
    const { scene } = useGLTF('/models/running_biometric_model.glb'); 
    const ref = useRef();

    useFrame((state, delta) => {
        if (ref.current) {
            // Subtle animation for visual interest
            ref.current.rotation.y += delta * 0.05; 
            ref.current.position.y = Math.sin(state.clock.elapsedTime * 0.5) * 0.1; 
        }
    });
    
    // 2. Return the model unconditionally once hooks are complete
    // The Suspense boundary handles the loading state and initial errors.
    return <primitive object={scene} ref={ref} scale={0.8} position={[0, -1, 0]} />;
}

const RunningModelBackground = () => {
    return (
        // Canvas is styled to cover the viewport and sit behind all UI (zIndex: -1)
        <Canvas 
            camera={{ position: [0, 0, 5], fov: 75 }} 
            style={{ 
                position: 'fixed', 
                top: 0, 
                left: 0, 
                width: '100vw', 
                height: '100vh', 
                zIndex: -1, 
                background: '#0d111c' // Ensures dark fallback color
            }}
        >
            {/* Suspense handles the asynchronous loading of the GLB model. 
                If RunnerModel throws an error (e.g., model not found), Suspense 
                will catch it and render its 'fallback' prop (which is null here). 
            */}
            <Suspense fallback={null}>
                {/* Lighting setup */}
                <ambientLight intensity={0.5} />
                <spotLight position={[10, 10, 10]} angle={0.3} penumbra={1} intensity={2} castShadow />
                
                {/* Environment for mood and reflections */}
                <Environment preset="night" blur={0.5} /> 

                <RunnerModel />
            </Suspense>
        </Canvas>
    );
};

export default RunningModelBackground;
